export function normalizeIsbn(v?: string | null): string {
  return (v || "").replace(/[^0-9Xx]/g, "");
}

export function normalizeTitle(v?: string | null): string {
  return (v || "").toLowerCase().replace(/\s+/g, " ").trim();
}

export function findAmazonLink(isbn?: string | null, title?: string | null): string | null {
  const cleanIsbn = normalizeIsbn(isbn);
  if (cleanIsbn && AMAZON_LINKS_BY_ISBN[cleanIsbn]) return AMAZON_LINKS_BY_ISBN[cleanIsbn];
  const t = normalizeTitle(title);
  if (t && AMAZON_LINKS_BY_TITLE[t]) return AMAZON_LINKS_BY_TITLE[t];
  return null;
}
